@charset "UTF-8";
@import url("https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600;700&display=swap");
/*======================================
Variables globales (Harmonisées)
======================================*/
:root {
  --font-primary: "Poppins", sans-serif;
  /* Couleurs Typographie */
  --color-text-dark: #39444D;
  --color-text-gray: #6B7280;
  --color-text-light: #9CA3AF;
  /* Couleurs UI */
  --color-bg: #ffffff;
  --color-bg-gray-light: #F9FAFB;
  --color-border: #E5E7EB;
  --color-pill-true-bg: #ECFDF5;
  --color-pill-true-text: #007A56;
  --color-primary: #82DB34;
  --color-primary-hover: #75C62F;
  --color-secondary: #204A83;
  --color-secondary-hover: #163F6B;
  --radius-main: 12px;
  --radius-sm: 8px;
  --radius-pill: 20px;
  --spacing: 1.5rem;
  --spacing-half: 0.75rem;
  --shadow-card: 0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03);
}

body {
  margin: 0;
  padding: 10px;
  font-family: var(--font-primary);
  background-color: transparent;
  color: var(--color-text-dark);
}

/*======================================
  Conteneur Principal (Header Bar)
======================================*/
.cta-offer {
  display: grid;
  grid-template-columns: 1fr 1.5fr 1fr 1.5fr; /* Ajustement des proportions */
  align-items: center;
  gap: var(--spacing);
  padding: var(--spacing-half) var(--spacing);
  width: 100%;
  max-width: 1000px;
  margin: 0 auto;
  background: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-main);
  box-shadow: var(--shadow-card);
  box-sizing: border-box;
}

/*======================================
  Logo
======================================*/
.cta-offer__logo {
  justify-self: center;
  align-self: center;
  border-radius: var(--radius-sm);
  padding: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  height: 60px; /* Hauteur fixe comme sur les cartes */
  width: 100%;
  max-width: 140px;
}

.cta-offer__logo img {
  display: block;
  width: 100%;
  height: 100%;
  object-fit: contain;
}

/*======================================
  Infos & Prix
======================================*/
.cta-offer__info {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
}

.cta-offer__title {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--color-text-dark);
  margin: 0;
  line-height: 1.2;
}

.cta-offer__price {
  display: flex;
  align-items: baseline;
  justify-content: center;
  gap: 2px;
  margin-top: 4px;
}

.cta-offer__price b {
  color: var(--color-text-dark);
  font-size: 1.8rem;
  font-weight: 600;
  letter-spacing: -0.02em;
}

.cta-offer__price span {
  color: var(--color-text-light);
  font-size: 0.9rem;
  font-weight: 500;
}

/*======================================
  Economies
======================================*/
.cta-offer__savings {
  display: flex;
  align-items: center;
  justify-content: center;
}

.savings-pill {
  padding: 4px 12px;
  border-radius: var(--radius-pill);
  font-size: 0.85rem;
  font-weight: 500;
  display: inline-block;
  text-align: center;
}

/*======================================
  Boutons d'action (Harmonisés)
======================================*/
.cta-offer__actions {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 8px;
  width: 100%;
}

.btn-cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 10px 24px;
  font-family: var(--font-primary);
  font-weight: 600;
  font-size: 1rem;
  border: none;
  border-radius: var(--radius-pill);
  cursor: pointer;
  color: white;
  transition: all 0.2s ease;
  width: 100%;
  max-width: 200px; /* Taille maximale fixe pour que les deux soient pareils */
  min-height: 44px; /* Hauteur minimum garantie */
  position: relative;
  overflow: hidden;
}

.btn-cta svg {
  width: 1.2em;
  height: 1.2em;
}

/* Effet de lumière commun aux deux boutons actifs */
.btn-cta:not(.btn-cta-disabled)::after {
  content: "";
  position: absolute;
  top: 0;
  left: -100%;
  width: 50%;
  height: 100%;
  background: linear-gradient(to right, rgba(255, 255, 255, 0) 0%, rgba(255, 255, 255, 0.4) 50%, rgba(255, 255, 255, 0) 100%);
  transform: skewX(-20deg);
  transition: left 0.6s ease-in-out;
}

.btn-cta:not(.btn-cta-disabled):hover::after {
  left: 150%;
}

/* Variations de couleurs */
.btn-cta--primary {
  background-color: var(--color-primary);
}

.btn-cta--primary:hover:not(.btn-cta-disabled) {
  background-color: var(--color-primary-hover);
}

.btn-cta--secondary {
  background-color: var(--color-secondary);
}

.btn-cta--secondary:hover:not(.btn-cta-disabled) {
  background-color: var(--color-secondary-hover);
}

/* Etat désactivé */
.btn-cta-disabled,
.btn-cta-disabled:hover {
  background-color: var(--color-border) !important;
  color: var(--color-text-light) !important;
  cursor: not-allowed;
  pointer-events: none;
}

/*======================================
  Responsive Mobile
======================================*/
@media screen and (max-width: 768px) {
  .cta-offer {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: var(--spacing);
    border-left-width: 4px; /* Rappel visuel comme sur la carte */
  }
  .cta-offer__logo {
    margin-bottom: var(--spacing-half);
  }
  .cta-offer__info {
    margin-bottom: var(--spacing-half);
  }
  .cta-offer__actions {
    flex-direction: row;
    justify-content: center;
    gap: var(--spacing-half);
    width: 100%;
  }
  .cta-offer__actions .btn-cta {
    flex: 1;
    max-width: none;
    font-size: 0.9rem; /* Légèrement plus petit sur mobile pour que ça rentre */
    padding: 10px 12px;
  }
}

