					className={"btn-cta btn-cta--secondary" + disabledClass}
					onClick={() => { if (!isDisabled) appsmith.triggerEvent("getDevis"); }}
					disabled={isDisabled}
				>
					Recevoir un devis
				</button>
			) : (
				<>
					<button 
						id="btn-validate" 
						className={"btn-cta btn-cta--primary" + disabledClass}
						onClick={() => { if (!isDisabled) appsmith.triggerEvent("validate"); }}
						disabled={isDisabled}
					>
						{svgValidate()} Poursuivre
					</button>
					<button 
						id="btn-callback" 
						className={"btn-cta btn-cta--secondary" + disabledClass}
						onClick={() => { if (!isDisabled) appsmith.triggerEvent("getCalled"); }}
						disabled={isDisabled}
					>
						{svgCall()} Être rappelé
					</button>
				</>
			)}
		</div>
	);
}

function App() {
	// Récupère la couleur de l'assureur pour la bordure gauche sur mobile
	const borderColor = appsmith.model.partner?.color || "var(--color-border)";

	return (
		<div 
			className="cta-offer"
			style={{ borderLeftColor: window.innerWidth <= 768 ? borderColor : "var(--color-border)" }}
		>
			{displayLogo()}
			{displayTitleAndPrice()}
			{appsmith.model.is_estimation ? <div></div> : displaySavings()}
			{displayActionsButtons(appsmith.model.is_estimation)}
		</div>
	);
}

// Gérer le redimensionnement pour la bordure gauche responsive (optionnel mais plus propre)
function RootApp() {
	const [width, setWidth] = React.useState(window.innerWidth);

	React.useEffect(() => {
		const handleResize = () => setWidth(window.innerWidth);
		window.addEventListener('resize', handleResize);
		return () => window.removeEventListener('resize', handleResize);
	}, []);

	return <App key={width} />;
}

appsmith.onReady(() => {
	ReactDOM.render(<RootApp />, document.getElementById("root"));
});

appsmith.onModelChange((newModel) => {
	ReactDOM.render(<RootApp />, document.getElementById("root"));
});

